const raw = items[0].json.result.data_array[0];
const weekStart = raw[0].split('T')[0];
const totalVolume = (parseFloat(raw[1]) / 1e6).toFixed(2);
const txCount = parseInt(raw[2]).toLocaleString();
const wowVolume = parseFloat(raw[3]);
const wowCount = parseFloat(raw[4]);
const cashInPct = parseFloat(raw[5]).toFixed(1);
const cashOutPct = parseFloat(raw[6]).toFixed(1);
const transferPct = parseFloat(raw[7]).toFixed(1);
const ratio = parseFloat(raw[8]).toFixed(2);
const volArrow = wowVolume >= 0 ? '▲' : '▼';
const cntArrow = wowCount >= 0 ? '▲' : '▼';

const top5 = JSON.parse(raw[9]);
const top5Lines = top5.map((a, i) => `  ${i + 1}. ${a.account_id} — ${a.tx_count} txns`).join('\n');

const message = `📅 *Weekly Transaction Report — w/c ${weekStart}*
──────────────────────────────
*Volume:*        $${totalVolume}M   ${volArrow} ${wowVolume}% WoW
*Transactions:*  ${txCount}   ${cntArrow} ${wowCount}% WoW

*Type Mix:*
  CASHIN:   ${cashInPct}%
  CASHOUT:  ${cashOutPct}%
  TRANSFER:  ${transferPct}%

*CASH_OUT / CASH_IN Ratio:*  ${ratio}

*Top 5 Accounts by Transaction Count:*
${top5Lines}`;

return [{ json: { message } }];
